import { RecordId } from "surrealdb";
import { jsonError, jsonResponse } from "../http/response";
import { logError, logInfo } from "../http/observability";
import { buildWorkspaceOverview, buildProjectContext, buildTaskContext } from "./context-builder";
import { resolveIntentContext, type IntentContextInput } from "./intent-context";
import { authenticateAndAuthorize } from "./mcp-dpop-auth";
import type { DPoPAuthResult } from "../oauth/types";
import type { DPoPVerificationDeps, LookupWorkspace } from "../oauth/dpop-middleware";
import type { LookupIdentity, LookupManager, ResolvedIdentity, ResolvedManager } from "../oauth/identity-lifecycle";
import { checkAuthority, checkAuthorityOrError } from "../iam/authority";
import type { AgentType } from "../chat/tools/types";
import {
  listProjectDecisions,
  getTaskDependencyTree,
  listProjectConstraints,
  listRecentChanges,
  createSubtask,
  updateTaskStatus,
  logImplementationNote,
  createAgentSession,
  endAgentSession,
  logCommit,
  getPluginTaskContext,
  getPluginProjectContext,
  validateTaskStatus,
  VALID_TASK_STATUSES,
} from "./mcp-queries";
import { createObservation } from "../observation/queries";
import {
  createSuggestion,
  acceptSuggestion,
  dismissSuggestion,
  deferSuggestion,
  convertSuggestion,
} from "../suggestion/queries";
import { OBSERVATION_TYPES, SUGGESTION_CATEGORIES, type ObservationType, type ObservationSeverity, type SuggestionCategory } from "../../shared/contracts";
import {
  createDecisionRecord,
  createQuestionRecord,
  getEntityDetail,
  parseRecordIdString,
  resolveWorkspaceProjectRecord,
  resolveWorkspaceFeatureRecord,
  listDecisionConstraintCandidates,
  searchEntitiesByEmbedding,
  isEntityInWorkspace,
  type GraphEntityTable,
} from "../graph/queries";
import { createEmbeddingVector } from "../graph/embeddings";
import type { ServerDependencies } from "../runtime/types";
import { requireRawId } from "./id-format";
import { processCommitTaskRefs } from "./commit-check";
import { generateObject } from "ai";
import { z } from "zod";
import { createIntent, createTrace, updateIntentStatus, getIntentById } from "../intent/intent-queries";
import type { IntentStatus } from "../intent/types";

type WorkspaceRow = {
  id: RecordId<"workspace", string>;
  name: string;
};

type ProjectRow = {
  id: RecordId<"project", string>;
  name: string;
};

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

async function parseJsonBody<T>(request: Request): Promise<T | Response> {
  try {
    return (await request.json()) as T;
  } catch {
    return jsonError("invalid JSON body", 400);
  }
}

const ENTITY_TABLES: GraphEntityTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question", "observation", "suggestion"];

function normalizeTokens(value: string): Set<string> {
  return new Set(
    value
      .toLowerCase()
      .replace(/[^a-z0-9\s]/g, " ")
      .split(/\s+/)
      .map((t) => t.trim())
      .filter((t) => t.length > 2),
  );
}

function hasTokenOverlap(a: Set<string>, b: Set<string>): boolean {
  for (const v of a) {
    if (b.has(v)) return true;
  }
  return false;
}

// ---------------------------------------------------------------------------
// Route handlers
// ---------------------------------------------------------------------------

export function createMcpRouteHandlers(deps: ServerDependencies) {
  const { surreal, config } = deps;

  // ---- Actor type mapping for authority checks ----
  const DEFAULT_AGENT_TYPE: AgentType = "code_agent";

  // ---- DPoP verification deps ----
  const lookupWorkspace: LookupWorkspace = async (workspaceId: string) => {
    const workspaceRecord = new RecordId("workspace", workspaceId);
    const workspace = await surreal.select<{ id: RecordId<"workspace", string>; name: string }>(workspaceRecord);
    if (!workspace) return undefined;

    // Resolve identity from workspace owner via membership
    const [identityRows] = await surreal.query<[Array<{ in: RecordId<"identity", string> }>]>(
      "SELECT in FROM member_of WHERE out = $ws LIMIT 1;",
      { ws: workspaceRecord },
    );
    const identityId = identityRows[0]?.in?.id as string | undefined;
    if (!identityId) return undefined;

    return { name: workspace.name, identityId };
  };

  const lookupIdentity: LookupIdentity = async (identityId: string) => {
    const [rows] = await surreal.query<[Array<{
      identityId: string;
      identityType: string;
      identityStatus?: string;
      managedBy?: string;
      revokedAt?: string;
    }>]>(
      `SELECT meta::id(id) AS identityId, type AS identityType, identity_status AS identityStatus, managed_by AS managedBy, revoked_at AS revokedAt FROM $identity;`,
      { identity: new RecordId("identity", identityId) },
    );
    const row = rows[0];
    if (!row) return undefined;
    return {
      identityId: row.identityId,
      identityType: row.identityType as ResolvedIdentity["identityType"],
      identityStatus: (row.identityStatus ?? "active") as ResolvedIdentity["identityStatus"],
      managedBy: row.managedBy,
      revokedAt: row.revokedAt ? new Date(row.revokedAt) : undefined,
    };
  };

  const lookupManager: LookupManager = async (managerId: string) => {
    const [rows] = await surreal.query<[Array<{ identityStatus?: string }>]>(
      `SELECT identity_status AS identityStatus FROM identity WHERE meta::id(id) = $managerId LIMIT 1;`,
      { managerId },
    );
    const row = rows[0];
    if (!row) return undefined;
    return {
      identityId: managerId,
      identityStatus: (row.identityStatus ?? "active") as ResolvedManager["identityStatus"],
    };
  };

  const dpopDeps: DPoPVerificationDeps = {
    asSigningKey: deps.asSigningKey,
    nonceCache: deps.nonceCache,
    lookupWorkspace,
    lookupIdentity,
    lookupManager,
  };

  // ---- Auth helper: DPoP + RAR verification ----
  async function requireAuth(request: Request): Promise<DPoPAuthResult | Response> {
    return authenticateAndAuthorize(request, dpopDeps);
  }

  // ---- Workspace helper (no auth - for legacy/unauthenticated routes) ----
  async function resolveWorkspaceById(workspaceId: string): Promise<{ workspaceRecord: RecordId<"workspace", string>; workspace: WorkspaceRow } | Response> {
    const workspaceRecord = new RecordId("workspace", workspaceId);
    const workspace = await surreal.select<WorkspaceRow>(workspaceRecord);
    if (!workspace) return jsonError("workspace not found", 404);
    return { workspaceRecord, workspace };
  }

  async function requireScopedRecord(record: RecordId<string, string>, workspaceRecord: RecordId<"workspace", string>, label: string): Promise<Response | undefined> {
    if (record.table.name === "agent_session") {
      const session = await surreal.select<{ workspace: RecordId<"workspace", string> }>(record as RecordId<"agent_session", string>);
      if (!session) {
        return jsonError(`${label} not found`, 404);
      }
      if ((session.workspace.id as string) !== (workspaceRecord.id as string)) {
        return jsonError(`${label} is outside workspace scope`, 404);
      }
      return undefined;
    }

    const scoped = await isEntityInWorkspace(surreal, workspaceRecord, record as RecordId<GraphEntityTable, string>);
    if (!scoped) {
      return jsonError(`${label} is outside workspace scope`, 404);
    }
    return undefined;
  }

  // =========================================================================
  // Setup
  // =========================================================================

  /** GET /api/mcp/:workspaceId/projects — List workspace projects */
  async function handleListProjects(workspaceId: string): Promise<Response> {
    const result = await resolveWorkspaceById(workspaceId);
    if (result instanceof Response) return result;

    const [projectRows] = await surreal
      .query<[ProjectRow[]]>(
        "SELECT id, name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
        { workspace: result.workspaceRecord },
      )
      .collect<[ProjectRow[]]>();

    return jsonResponse({
      workspace: { id: workspaceId, name: result.workspace.name },
      projects: projectRows.map((p) => ({ id: p.id.id as string, name: p.name })),
    }, 200);
  }

  // =========================================================================
  // Tier 1 — Read
  // =========================================================================

  /** POST /api/mcp/:workspaceId/workspace-context — Lightweight orientation (no required params) */
  async function handleWorkspaceContext(workspaceId: string, request: Request): Promise<Response> {
    const auth = await requireAuth(request);
    if (auth instanceof Response) return auth;


    const body = await parseJsonBody<{ session_id?: string }>(request);
    if (body instanceof Response) return body;

    try {
      const overview = await buildWorkspaceOverview({
        surreal,
        workspaceRecord: auth.workspaceRecord,
        workspaceName: auth.workspaceName,
        ...(body.session_id ? { excludeSessionId: requireRawId(body.session_id, "session_id") } : {}),
      });
      logInfo("mcp.workspace-context.built", "Workspace overview assembled", { workspaceId, projectCount: overview.projects.length });
      return jsonResponse(overview, 200);
    } catch (error) {
      logError("mcp.workspace-context.failed", "Failed to build workspace overview", error);
      return jsonError("failed to build workspace overview", 500);
    }
  }

  /** POST /api/mcp/:workspaceId/context — Intent-based context resolution */
  async function handleIntentContext(workspaceId: string, request: Request): Promise<Response> {
    const auth = await requireAuth(request);
    if (auth instanceof Response) return auth;

    const body = await parseJsonBody<IntentContextInput>(request);
    if (body instanceof Response) return body;

    if (!body.intent || typeof body.intent !== "string") {
      return jsonError("intent is required", 400);
    }

    try {
      const result = await resolveIntentContext({
        surreal,
        embeddingModel: deps.embeddingModel,
        embeddingDimension: config.embeddingDimension,
        workspaceRecord: auth.workspaceRecord,
        workspaceName: auth.workspaceName,
        intent: body.intent,
        cwd: body.cwd,
        paths: body.paths,
      });
      logInfo("mcp.intent-context.resolved", "Intent context resolved", { workspaceId, level: result.level });
      return jsonResponse(result, 200);
    } catch (error) {
      logError("mcp.intent-context.failed", "Failed to resolve intent context", error);
      return jsonError("failed to resolve intent context", 500);
    }
  }

  /** POST /api/mcp/:workspaceId/project-context — Full project context (project_id required) */
  async function handleProjectContext(workspaceId: string, request: Request): Promise<Response> {
    const auth = await requireAuth(request);
    if (auth instanceof Response) return auth;


    const body = await parseJsonBody<{ project_id: string; task_id?: string; since?: string; session_id?: string; mode?: string }>(request);
    if (body instanceof Response) return body;
    if (!body.project_id) return jsonError("project_id is required", 400);

    let projectId: string;
    let taskId: string | undefined;
    let sessionId: string | undefined;
    try {
      projectId = requireRawId(body.project_id, "project_id");
      taskId = body.task_id ? requireRawId(body.task_id, "task_id") : undefined;
      sessionId = body.session_id ? requireRawId(body.session_id, "session_id") : undefined;
    } catch (error) {
      return jsonError(error instanceof Error ? error.message : "invalid id format", 400);
    }

    const projectRecord = new RecordId("project", projectId);

    // Plugin mode: return flat project fields only
    if (!sessionId || body.mode === "plugin") {
      try {
        const pluginContext = await getPluginProjectContext({
          surreal,
          workspaceRecord: auth.workspaceRecord,
          projectRecord,
        });
        if (!pluginContext) return jsonError("project not found", 404);
        logInfo("mcp.project-context.plugin", "Plugin project context returned", { workspaceId, projectId });
        return jsonResponse(pluginContext, 200);
      } catch (error) {
        logError("mcp.project-context.plugin.failed", "Failed to get plugin project context", error);
        return jsonError("failed to get project context", 500);
      }
    }

    // Rich mode: full context packet for agent sessions
    const scopedProjectError = await requireScopedRecord(projectRecord, auth.workspaceRecord, "project");
    if (scopedProjectError) return scopedProjectError;
    if (taskId) {
      const scopedTaskError = await requireScopedRecord(new RecordId("task", taskId), auth.workspaceRecord, "task");
      if (scopedTaskError) return scopedTaskError;
    }

    try {
      const contextPacket = await buildProjectContext({
        surreal,
        workspaceRecord: auth.workspaceRecord,
        workspaceName: auth.workspaceName,
        projectRecord,
        ...(taskId ? { taskId } : {}),
        since: body.since,
        ...(sessionId ? { excludeSessionId: sessionId } : {}),
      });

      logInfo("mcp.project-context.built", "Project context assembled", {
        workspaceId,
        projectId,
        taskId,
        decisionsCount:
          contextPacket.decisions.confirmed.length +
          contextPacket.decisions.provisional.length +
          contextPacket.decisions.contested.length,
        tasksCount: contextPacket.active_tasks.length,
      });

      return jsonResponse(contextPacket, 200);
    } catch (error) {
      logError("mcp.project-context.failed", "Failed to build project context", error);
      return jsonError("failed to build project context", 500);
    }
  }

  /** POST /api/mcp/:workspaceId/task-context — Task-focused context (task_id required, project resolved) */
  async function handleTaskContext(workspaceId: string, request: Request): Promise<Response> {
    const auth = await requireAuth(request);
    if (auth instanceof Response) return auth;


    const body = await parseJsonBody<{ task_id: string; session_id?: string; mode?: string }>(request);
    if (body instanceof Response) return body;
    if (!body.task_id) return jsonError("task_id is required", 400);

    let taskId: string;
    let sessionId: string | undefined;
    try {
      taskId = requireRawId(body.task_id, "task_id");
      sessionId = body.session_id ? requireRawId(body.session_id, "session_id") : undefined;
    } catch (error) {
      return jsonError(error instanceof Error ? error.message : "invalid id format", 400);
    }

    const taskRecord = new RecordId("task", taskId);

    // Plugin mode: return flat task fields only
    if (!sessionId || body.mode === "plugin") {
      const pluginContext = await getPluginTaskContext({
        surreal,
        workspaceRecord: auth.workspaceRecord,
        taskRecord,
      });
      if (!pluginContext) return jsonError("task not found", 404);
      logInfo("mcp.task-context.plugin", "Plugin task context returned", { workspaceId, taskId });
      return jsonResponse(pluginContext, 200);
    }

    // Rich mode: full context packet for agent sessions
    const scopedTaskError = await requireScopedRecord(taskRecord, auth.workspaceRecord, "task");
    if (scopedTaskError) return scopedTaskError;

    try {
      const taskContext = await buildTaskContext({
        surreal,
        workspaceRecord: auth.workspaceRecord,
        workspaceName: auth.workspaceName,
        taskId,
        ...(sessionId ? { excludeSessionId: sessionId } : {}),
      });

      logInfo("mcp.task-context.built", "Task context assembled", { workspaceId, taskId });
      return jsonResponse(taskContext, 200);
    } catch (error) {
      logError("mcp.task-context.failed", "Failed to build task context", error);
      return jsonError("failed to build task context", 500);
    }
  }

  /** POST /api/mcp/:workspaceId/decisions — Active decisions, optionally scoped to project/area */
  async function handleGetDecisions(_workspaceId: string, request: Request): Promise<Response> {
    const auth = await requireAuth(request);
    if (auth instanceof Response) return auth;


    const body = await parseJsonBody<{ project_id?: string; area?: string }>(request);
    if (body instanceof Response) return body;

    let projectRecord: RecordId<"project", string> | undefined;
    if (body.project_id) {
      let projectId: string;
      try {
        projectId = requireRawId(body.project_id, "project_id");
      } catch (error) {
        return jsonError(error instanceof Error ? error.message : "invalid project_id", 400);
      }
      projectRecord = new RecordId("project", projectId);
      const scopedProjectError = await requireScopedRecord(projectRecord, auth.workspaceRecord, "project");
      if (scopedProjectError) return scopedProjectError;
    }

    const decisions = await listProjectDecisions({
      surreal,
      workspaceRecord: auth.workspaceRecord,
      projectRecord,
      area: body.area,
    });

    return jsonResponse(decisions, 200);
  }

  /** POST /api/mcp/:workspaceId/tasks/dependencies — Task dependency tree */
  async function handleGetTaskDependencies(_workspaceId: string, request: Request): Promise<Response> {
    const auth = await requireAuth(request);
    if (auth instanceof Response) return auth;


    const body = await parseJsonBody<{ task_id: string }>(request);
    if (body instanceof Response) return body;
    if (!body.task_id) return jsonError("task_id is required", 400);
    let taskId: string;
    try {
      taskId = requireRawId(body.task_id, "task_id");
    } catch (error) {
      return jsonError(error instanceof Error ? error.message : "invalid task_id", 400);
    }

    const taskRecord = new RecordId("task", taskId);
    const scopedTaskError = await requireScopedRecord(taskRecord, auth.workspaceRecord, "task");
    if (scopedTaskError) return scopedTaskError;
    const tree = await getTaskDependencyTree({ surreal, workspaceRecord: auth.workspaceRecord, taskRecord });

    return jsonResponse(tree, 200);
  }

  /** POST /api/mcp/:workspaceId/constraints — Architecture constraints, optionally scoped to project */
  async function handleGetConstraints(_workspaceId: string, request: Request): Promise<Response> {
    const auth = await requireAuth(request);
    if (auth instanceof Response) return auth;


    const body = await parseJsonBody<{ project_id?: string; area?: string }>(request);
    if (body instanceof Response) return body;

    let projectRecord: RecordId<"project", string> | undefined;
    if (body.project_id) {
      let projectId: string;
      try {
        projectId = requireRawId(body.project_id, "project_id");
      } catch (error) {
        return jsonError(error instanceof Error ? error.message : "invalid project_id", 400);
      }
      projectRecord = new RecordId("project", projectId);
      const scopedProjectError = await requireScopedRecord(projectRecord, auth.workspaceRecord, "project");
      if (scopedProjectError) return scopedProjectError;
    }

    const constraints = await listProjectConstraints({
      surreal,
      workspaceRecord: auth.workspaceRecord,
      projectRecord,
      area: body.area,
    });

    return jsonResponse({ constraints }, 200);
  }

  /** POST /api/mcp/:workspaceId/changes — Recent changes since timestamp */
  async function handleGetChanges(_workspaceId: string, request: Request): Promise<Response> {
    const auth = await requireAuth(request);
    if (auth instanceof Response) return auth;


    const body = await parseJsonBody<{ project_id?: string; since: string }>(request);
    if (body instanceof Response) return body;
    if (!body.since) return jsonError("since is required", 400);

    let projectRecord: RecordId<"project", string> | undefined;
    if (body.project_id) {
      let projectId: string;
      try {
        projectId = requireRawId(body.project_id, "project_id");
      } catch (error) {
        return jsonError(error instanceof Error ? error.message : "invalid project_id", 400);
      }
      const record = new RecordId("project", projectId);
      const scopedProjectError = await requireScopedRecord(record, auth.workspaceRecord, "project");
      if (scopedProjectError) return scopedProjectError;
      projectRecord = record;
    }

    const changes = await listRecentChanges({
      surreal,
      workspaceRecord: auth.workspaceRecord,
      projectRecord,
      since: body.since,
    });

    return jsonResponse({ changes }, 200);
  }

  /** GET /api/mcp/:workspaceId/entities/:entityId — Entity detail */
  async function handleGetEntityDetail(_workspaceId: string, entityId: string, request: Request): Promise<Response> {
    const auth = await requireAuth(request);
    if (auth instanceof Response) return auth;


    try {
      const entityRecord = parseRecordIdString(entityId, ENTITY_TABLES);
      const detail = await getEntityDetail({
        surreal,
        workspaceRecord: auth.workspaceRecord,
        entityRecord,
      });

      return jsonResponse(detail, 200);
    } catch {
      return jsonError(`entity not found: ${entityId}`, 404);
    }
  }

  // =========================================================================
  // Tier 2 — Reason
  // =========================================================================

  /** POST /api/mcp/:workspaceId/decisions/resolve — Infer decision from graph */
  async function handleResolveDecision(_workspaceId: string, request: Request): Promise<Response> {
    const auth = await requireAuth(request);
    if (auth instanceof Response) return auth;

    const perm = await checkAuthority({ surreal, agentType: DEFAULT_AGENT_TYPE, action: "create_decision", workspaceRecord: auth.workspaceRecord });
    const denied = checkAuthorityOrError(perm, "create_decision", auth.actorType);
    if (denied) return denied;

    const body = await parseJsonBody<{
      question: string;
      options?: string[];
      context?: { project?: string; feature?: string };
    }>(request);
    if (body instanceof Response) return body;
    if (!body.question) return jsonError("question is required", 400);

    // Embed the question and search for related decisions
    const queryEmbedding = await createEmbeddingVector(
      deps.embeddingModel,
      body.question,
      config.embeddingDimension,
    );

    if (!queryEmbedding) {
      return jsonResponse({
        decision: undefined,
        confidence: 0,
        status: "unresolved",
        rationale: "Could not create embedding for question",
        sources: [],
      }, 200);
    }

    const projectRecord = body.context?.project
      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.context.project })
      : undefined;

    const candidates = await searchEntitiesByEmbedding({
      surreal,
      workspaceRecord: auth.workspaceRecord,
      queryEmbedding,
      kinds: ["decision"],
      ...(projectRecord ? { projectRecord } : {}),
      limit: 10,
    });

    // Check if any existing decision resolves the question
    const questionTokens = normalizeTokens(body.question);
    const relevant = candidates.filter((c) => {
      const tokens = normalizeTokens(c.name);
      return c.score >= 0.78 && hasTokenOverlap(questionTokens, tokens);
    });

    if (relevant.length > 0) {
      const best = relevant[0];
      return jsonResponse({
        decision: best.name,
        confidence: Number(best.score.toFixed(4)),
        status: best.status ?? "unknown",
        rationale: `Existing ${best.status} decision found with ${(best.score * 100).toFixed(1)}% similarity`,
        sources: relevant.map((r) => ({ id: `${r.kind}:${r.id}`, name: r.name, score: Number(r.score.toFixed(4)) })),
      }, 200);
    }

    return jsonResponse({
      decision: undefined,
      confidence: 0,
      status: "unresolved",
      rationale: "No existing decision found that resolves this question",
      sources: candidates.slice(0, 5).map((c) => ({
        id: `${c.kind}:${c.id}`,
        name: c.name,
        score: Number(c.score.toFixed(4)),
      })),
    }, 200);
  }

  /** POST /api/mcp/:workspaceId/constraints/check — Check proposed action */
  async function handleCheckConstraints(_workspaceId: string, request: Request): Promise<Response> {
    const auth = await requireAuth(request);
    if (auth instanceof Response) return auth;


    const body = await parseJsonBody<{ proposed_action: string; project?: string }>(request);
    if (body instanceof Response) return body;
    if (!body.proposed_action) return jsonError("proposed_action is required", 400);

    const queryEmbedding = await createEmbeddingVector(
      deps.embeddingModel,
      body.proposed_action,
      config.embeddingDimension,
    );

    if (!queryEmbedding) {
      return jsonResponse({ hard_conflicts: [], soft_tensions: [], supporting: [], proceed: true }, 200);
    }

    const projectRecord = body.project
      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.project })
      : undefined;

    const candidates = await listDecisionConstraintCandidates({
      surreal,
      workspaceRecord: auth.workspaceRecord,
      queryEmbedding,
      ...(projectRecord ? { projectRecord } : {}),
      limit: 14,
    });

    const actionTokens = normalizeTokens(body.proposed_action);
    const hardConflicts: Array<{ id: string; name: string; score: number; reason: string }> = [];
    const softTensions: Array<{ id: string; name: string; score: number; reason: string }> = [];
    const supporting: Array<{ id: string; name: string; score: number; reason: string }> = [];

    for (const candidate of candidates) {
      const candidateTokens = normalizeTokens(candidate.name);
      const overlap = hasTokenOverlap(actionTokens, candidateTokens);
      const status = candidate.status?.toLowerCase();

      if (candidate.kind === "decision" && overlap && (status === "contested" || status === "superseded")) {
        hardConflicts.push({
          id: `${candidate.kind}:${candidate.id}`,
          name: candidate.name,
          score: Number(candidate.score.toFixed(4)),
          reason: `Decision is marked ${status}.`,
        });
        continue;
      }

      if (candidate.kind === "decision" && candidate.score >= 0.86 && overlap) {
        supporting.push({
          id: `${candidate.kind}:${candidate.id}`,
          name: candidate.name,
          score: Number(candidate.score.toFixed(4)),
          reason: "High-similarity decision aligns with proposed action.",
        });
        continue;
      }

      if (candidate.score >= 0.72) {
        softTensions.push({
          id: `${candidate.kind}:${candidate.id}`,
          name: candidate.name,
          score: Number(candidate.score.toFixed(4)),
          reason: overlap
            ? "Related decision/question may require consistency checks."
            : "Semantically related context may be affected.",
        });
      }
    }

    return jsonResponse({ hard_conflicts: hardConflicts, soft_tensions: softTensions, supporting, proceed: hardConflicts.length === 0 }, 200);
  }

